/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Each validator returns an object:
 *   { valid: boolean, errors: string[] }
 *
 * Validation rules applied consistently across all endpoints:
 *   - id       : must be a positive integer (numeric)
 *   - name     : required string, 1–100 characters
 *   - email    : required string, valid email format, max 254 characters
 */

// ---------------------------------------------------------------------------
// Low-level field validators
// ---------------------------------------------------------------------------

/**
 * Validate a user `id` value (route param or body).
 * Accepts a string from req.params or a raw number from req.body.
 * Returns true when the coerced value is a positive integer.
 */
function isValidId(value) {
  if (value === undefined || value === null || value === '') return false;
  const num = Number(value);
  return Number.isInteger(num) && num > 0;
}

/**
 * Validate a `name` string: must be a non-empty string, 1–100 chars.
 */
function isValidName(value) {
  return typeof value === 'string' && value.trim().length >= 1 && value.trim().length <= 100;
}

/**
 * Validate an `email` string:
 *   - must be a string
 *   - max 254 characters (RFC 5321 / RFC 5322 limit)
 *   - must match a standard email pattern
 */
function isValidEmail(value) {
  if (typeof value !== 'string') return false;
  if (value.length > 254) return false;
  // Pattern: local@domain.tld — covers the vast majority of valid addresses
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRe.test(value);
}

// ---------------------------------------------------------------------------
// Composite validators used by route handlers
// ---------------------------------------------------------------------------

/**
 * Validate a numeric route param (e.g. req.params.id).
 * Returns { valid, errors }.
 */
function validateIdParam(params) {
  const errors = [];

  if (params.id === undefined || params.id === '') {
    errors.push('id is required');
  } else if (!isValidId(params.id)) {
    errors.push('id must be a positive integer');
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate the request body for creating a new user.
 * Required fields: name, email.
 * Returns { valid, errors }.
 */
function validateCreateUser(body) {
  const errors = [];

  // ---- name ----------------------------------------------------------------
  if (body.name === undefined || body.name === null) {
    errors.push('name is required');
  } else if (typeof body.name !== 'string') {
    errors.push('name must be a string');
  } else if (body.name.trim().length < 1) {
    errors.push('name must be at least 1 character');
  } else if (body.name.trim().length > 100) {
    errors.push('name must be at most 100 characters');
  }

  // ---- email ---------------------------------------------------------------
  if (body.email === undefined || body.email === null) {
    errors.push('email is required');
  } else if (typeof body.email !== 'string') {
    errors.push('email must be a string');
  } else if (body.email.length > 254) {
    errors.push('email must be at most 254 characters');
  } else if (!isValidEmail(body.email)) {
    errors.push('email must be a valid email address');
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate the request body for updating an existing user.
 * At least one of name or email must be provided; each provided field is
 * fully validated.
 * Returns { valid, errors }.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return { valid: false, errors };
  }

  // ---- name (optional, but validated when present) -------------------------
  if (hasName) {
    if (typeof body.name !== 'string') {
      errors.push('name must be a string');
    } else if (body.name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (body.name.trim().length > 100) {
      errors.push('name must be at most 100 characters');
    }
  }

  // ---- email (optional, but validated when present) ------------------------
  if (hasEmail) {
    if (typeof body.email !== 'string') {
      errors.push('email must be a string');
    } else if (body.email.length > 254) {
      errors.push('email must be at most 254 characters');
    } else if (!isValidEmail(body.email)) {
      errors.push('email must be a valid email address');
    }
  }

  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level (useful for unit tests)
  isValidId,
  isValidName,
  isValidEmail,
  // Composite (used by route handlers)
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
};

