/**
 * Validation helper module.
 *
 * Each exported function validates a specific set of fields and returns an
 * array of human-readable error strings.  An empty array means "valid".
 *
 * Usage inside a route handler:
 *
 *   const errors = validateUserBody(req.body);
 *   if (errors.length) return res.status(400).json({ errors });
 */

// ---------------------------------------------------------------------------
// Primitive validators (reusable building blocks)
// ---------------------------------------------------------------------------

/**
 * Returns true when `value` is a finite integer (or a string that represents
 * one), i.e. the kind of value we accept as a URL :id parameter.
 */
function isNumericId(value) {
  if (value === null || value === undefined || value === '') return false;
  // Allow numeric strings produced by URL param parsing as well as real numbers.
  const n = Number(value);
  return Number.isFinite(n) && Number.isInteger(n) && n > 0;
}

/**
 * Returns true when `value` is a non-empty string.
 */
function isString(value) {
  return typeof value === 'string';
}

/**
 * Minimal RFC-5321 / HTML5 e-mail pattern.
 * Accepts virtually every real-world address without being overly permissive.
 */
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function isValidEmail(value) {
  return isString(value) && EMAIL_REGEX.test(value);
}

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validates the `id` coming from a URL parameter (req.params.id).
 * Returns an array of error strings (empty = valid).
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point running further checks
  }

  if (!isNumericId(id)) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validates the `name` field from a request body.
 * Returns an array of error strings (empty = valid).
 *
 * @param {*}       value      - The raw value from req.body.name
 * @param {boolean} required   - When true, an absent/blank value is an error.
 */
function validateName(value, required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (!isString(value)) {
    errors.push('name must be a string');
    return errors;
  }

  if (value.length < 1) {
    errors.push('name must be at least 1 character');
  }
  if (value.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validates the `email` field from a request body.
 * Returns an array of error strings (empty = valid).
 *
 * @param {*}       value      - The raw value from req.body.email
 * @param {boolean} required   - When true, an absent/blank value is an error.
 */
function validateEmail(value, required = true) {
  const errors = [];

  const missing = value === undefined || value === null || value === '';
  if (missing) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (!isString(value)) {
    errors.push('email must be a string');
    return errors;
  }

  if (!isValidEmail(value)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  if (value.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators (one per endpoint / use-case)
// ---------------------------------------------------------------------------

/**
 * Validates URL parameter `id`.
 * Used by: GET /users/:id, PUT /users/:id, DELETE /users/:id
 */
function validateUserParams(params) {
  return validateId(params.id);
}

/**
 * Validates the request body for POST /users (create).
 * Both `name` and `email` are required.
 */
function validateCreateUserBody(body) {
  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validates the request body for PUT /users/:id (full replace).
 * Both `name` and `email` are required.
 */
function validateUpdateUserBody(body) {
  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validates the request body for PATCH /users/:id (partial update).
 * At least one of `name` or `email` must be supplied; present fields are
 * validated with their normal rules.
 */
function validatePatchUserBody(body) {
  const errors = [];

  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for a partial update');
    return errors;
  }

  if (hasName) errors.push(...validateName(body.name, true));
  if (hasEmail) errors.push(...validateEmail(body.email, true));

  return errors;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Primitive helpers (exported for unit-testing convenience)
  isNumericId,
  isString,
  isValidEmail,
  // Field validators
  validateId,
  validateName,
  validateEmail,
  // Composite / endpoint validators
  validateUserParams,
  validateCreateUserBody,
  validateUpdateUserBody,
  validatePatchUserBody,
};

