/**
 * validation.js
 * Reusable input-validation helpers for API endpoints.
 */

'use strict';

// RFC 5321 / RFC 5322 practical email pattern (local@domain.tld)
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route/query parameter that must be a positive integer id.
 *
 * @param {string|number} value  The raw value (often still a string from req.params)
 * @returns {string[]}           Array of error messages (empty = valid)
 */
function validateId(value) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push('id is required');
    return errors;
  }

  // Must consist solely of digits (no floats, no negative signs)
  if (!/^\d+$/.test(String(value))) {
    errors.push('id must be a positive integer');
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the user-object fields found in a request body.
 *
 * @param {object}  body
 * @param {object}  [options]
 * @param {boolean} [options.requireAll=true]  When true every field is required;
 *                                             when false only supplied fields are checked
 *                                             (useful for PATCH-style partial updates).
 * @returns {string[]}  Array of error messages (empty = valid)
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];

  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    errors.push('request body must be a JSON object');
    return errors;
  }

  const { name, email } = body;

  // ── name ────────────────────────────────────────────────────────────────
  if (name === undefined) {
    if (requireAll) errors.push('name is required');
  } else {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (name.length > 100) {
      errors.push('name must be at most 100 characters');
    }
  }

  // ── email ────────────────────────────────────────────────────────────────
  if (email === undefined) {
    if (requireAll) errors.push('email is required');
  } else {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (email.length > 254) {
      errors.push('email must be at most 254 characters');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address (e.g. user@example.com)');
    }
  }

  return errors;
}

/**
 * Send a 400 response that lists every validation failure.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {import('express').Response}
 */
function sendValidationError(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

