'use strict';

const express = require('express');
const { validateId, validateUserBody, sendValidationError } = require('./validation');

const app = express();

// ── Body parsing ────────────────────────────────────────────────────────────
app.use(express.json());

// In-memory store (stands in for a real database)
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ── GET /health ─────────────────────────────────────────────────────────────
// No user input → nothing to validate.
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ── GET /users ───────────────────────────────────────────────────────────────
// No user input → nothing to validate.
app.get('/users', (req, res) => {
  res.json(users);
});

// ── GET /users/:id ───────────────────────────────────────────────────────────
// Validates: id is a positive integer.
app.get('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  const user = users.find(u => u.id === Number(req.params.id));
  if (!user) return res.status(404).json({ error: 'User not found' });

  res.json(user);
});

// ── POST /users ──────────────────────────────────────────────────────────────
// Validates: name (required, string, 1-100 chars) and
//            email (required, string, valid format, max 254 chars).
app.post('/users', (req, res) => {
  const bodyErrors = validateUserBody(req.body, { requireAll: true });
  if (bodyErrors.length) return sendValidationError(res, bodyErrors);

  const { name, email } = req.body;
  const user = { id: nextId++, name: name.trim(), email };
  users.push(user);

  res.status(201).json(user);
});

// ── PUT /users/:id ───────────────────────────────────────────────────────────
// Validates: id is a positive integer, plus all body fields (full replacement).
app.put('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  const bodyErrors = validateUserBody(req.body, { requireAll: true });
  if (bodyErrors.length) return sendValidationError(res, bodyErrors);

  const id = Number(req.params.id);
  const index = users.findIndex(u => u.id === id);
  if (index === -1) return res.status(404).json({ error: 'User not found' });

  const { name, email } = req.body;
  users[index] = { id, name: name.trim(), email };

  res.json(users[index]);
});

// ── PATCH /users/:id ─────────────────────────────────────────────────────────
// Validates: id is a positive integer; only the fields supplied in the body are
// validated (partial update — at least one field must be present).
app.patch('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  // At least one field must be supplied
  const { name, email } = req.body || {};
  if (name === undefined && email === undefined) {
    return sendValidationError(res, ['at least one of name or email must be provided']);
  }

  const bodyErrors = validateUserBody(req.body, { requireAll: false });
  if (bodyErrors.length) return sendValidationError(res, bodyErrors);

  const id = Number(req.params.id);
  const index = users.findIndex(u => u.id === id);
  if (index === -1) return res.status(404).json({ error: 'User not found' });

  if (name !== undefined) users[index].name = name.trim();
  if (email !== undefined) users[index].email = email;

  res.json(users[index]);
});

// ── DELETE /users/:id ────────────────────────────────────────────────────────
// Validates: id is a positive integer.
app.delete('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  const id = Number(req.params.id);
  const index = users.findIndex(u => u.id === id);
  if (index === -1) return res.status(404).json({ error: 'User not found' });

  const [deleted] = users.splice(index, 1);
  res.json({ message: 'User deleted', user: deleted });
});

// ── Start ────────────────────────────────────────────────────────────────────
app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

